type RawRow = {
  tool_name: string
  tool_call_status: string
  trial: number
  latency_ms: number
  input_bytes: number
  output_bytes: number
}

function summarize(rows: RawRow[]) {
  const groups = [...new Set(rows.map((row) => `${row.tool_name}::${row.tool_call_status}`))].map((key) => {
    const values = rows.filter((row) => `${row.tool_name}::${row.tool_call_status}` === key)
    const latencies = values.map((row) => row.latency_ms).sort((a, b) => a - b)
    const sum = latencies.reduce((acc, item) => acc + item, 0)
    const avg = sum / latencies.length
    return {
      tool_name: values[0]!.tool_name,
      tool_call_status: values[0]!.tool_call_status,
      runs: values.length,
      min_latency_ms: latencies[0]!,
      p50_latency_ms: latencies[Math.floor(latencies.length / 2)]!,
      max_latency_ms: latencies[latencies.length - 1]!,
      avg_latency_ms: Number(avg.toFixed(2)),
      avg_input_bytes: Number((values.reduce((acc, item) => acc + item.input_bytes, 0) / values.length).toFixed(2)),
      avg_output_bytes: Number((values.reduce((acc, item) => acc + item.output_bytes, 0) / values.length).toFixed(2)),
    }
  })
  return groups.sort((a, b) => a.tool_name.localeCompare(b.tool_name))
}

async function runCase(runID: number, toolCase: (typeof toolCases)[number]) {
  return Effect.runPromise(
    provideTmpdirServer(
      ({ dir, llm }) =>
        Effect.gen(function* () {
          yield* Effect.promise(() => toolCase.setup(dir))
          yield* Effect.promise(() => toolCase.queue(llm, dir))

          const prompt = yield* SessionPrompt.Service
          const sessions = yield* Session.Service
          const bus = yield* Bus.Service
          const session = yield* sessions.create({
            title: `Latency ${toolCase.tool_name} ${runID}`,
            permission: [{ permission: "*", pattern: "*", action: "allow" }],
          })
          const seen = yield* Deferred.make<void>()
          let metric:
            | {
                tool_name: string
                tool_call_status: string
                latency_ms: number
                input_bytes: number
                output_bytes: number
              }
            | undefined
          const off = yield* bus.subscribeCallback(Metrics.ToolCall, (evt) => {
            if (evt.properties.sessionID !== session.id) return
            metric = evt.properties
            Deferred.doneUnsafe(seen, Effect.void)
          })

          yield* prompt.prompt({
            sessionID: session.id,
            agent: "build",
            noReply: true,
            parts: [{ type: "text", text: toolCase.prompt_text }],
          })
          const fiber = yield* prompt.loop({ sessionID: session.id }).pipe(Effect.forkChild)
          yield* Deferred.await(seen)
          const exit = yield* Fiber.await(fiber)
          off()
          if (Exit.isFailure(exit)) return yield* Effect.fail(Cause.squash(exit.cause))
          if (!metric) return yield* Effect.fail(new Error(`no tool metric for ${toolCase.tool_name}`))
          return {
            tool_name: metric.tool_name,
            tool_call_status: metric.tool_call_status,
            latency_ms: metric.latency_ms,
            input_bytes: metric.input_bytes,
            output_bytes: metric.output_bytes,
          }
        }),
      { git: true, config: providerCfg },
    ).pipe(Effect.provide(runtime)),
  )
}

const outDir = path.resolve(import.meta.dir)
