  csvPath,
  [
    "tool_name,tool_call_status,runs,min_latency_ms,p50_latency_ms,max_latency_ms,avg_latency_ms,avg_input_bytes,avg_output_bytes",
    ...summaryRows.map((row) =>
      [
        row.tool_name,
        row.tool_call_status,
        row.runs,
        row.min_latency_ms,
        row.p50_latency_ms,
        row.max_latency_ms,
        row.avg_latency_ms,
        row.avg_input_bytes,
        row.avg_output_bytes,
      ].join(","),
    ),
  ].join("\n") + "\n",
)
await Bun.write(summaryPath, JSON.stringify(summaryRows, null, 2))

console.log(JSON.stringify({ rawPath, csvPath, summaryPath, rows: rawRows.length }, null, 2))

