function provideCaseEffect<A>(
  fn: (
    dir: string,
    sessionID: SessionID,
    ctx: CaseContext["ctx"],
    getTool: CaseContext["getTool"],
  ) => Effect.Effect<A>,
) {
  return provideTmpdirInstance(
    (dir) =>
      Effect.gen(function* () {
        const sessionSvc = yield* Session.Service
        const registry = yield* ToolRegistry.Service
        const chat = yield* sessionSvc.create({
          title: "tool-case",
          permission: [{ permission: "*", pattern: "*", action: "allow" }],
        })
        const callID = `call_${Math.random().toString(36).slice(2)}`
        const ctx = {
          sessionID: chat.id,
          messageID: MessageID.ascending(),
          callID,
          agent: "build",
          abort: AbortSignal.any([]),
          messages: [] as never[],
          metadata: () => Effect.void,
          ask: () => Effect.void,
        }
        const getTool = (id: string) =>
          Effect.gen(function* () {
            const all = yield* registry.all()
            const tool = all.find((item) => item.id === id)
            if (!tool) return yield* Effect.fail(new Error(`tool not found: ${id}`))
            return tool
          })
        return yield* fn(dir, chat.id, ctx, getTool)
      }),
    { git: true, config: cfg },
  ).pipe(Effect.provide(runtime), Effect.scoped)
}

async function runCase(toolCase: ToolCase) {
  const started = performance.now()
  const exit = await Effect.runPromiseExit(
    provideCaseEffect((dir, sessionID, ctx, getTool) =>
      Effect.promise(() => toolCase.run({ dir, sessionID, ctx, getTool })),
    ),
  )
  const elapsed_ms = Number((performance.now() - started).toFixed(2))
  if (Exit.isSuccess(exit)) {
    return {
      tool_id: toolCase.tool_id,
      requested_name: toolCase.requested_name ?? toolCase.tool_id,
      expectation: toolCase.expectation,
      executed: true,
      ok: toolCase.expectation === "success",
      status: toolCase.expectation === "success" ? "success" : "unexpected_success",
      elapsed_ms,
      note: toolCase.note,
      title: exit.value.title,
      output_excerpt: exit.value.output.slice(0, 160).replaceAll("\n", "\\n"),
      error: "",
    }
  }
  const error = String(Exit.isFailure(exit) ? exit.cause : "unknown error")
  return {
    tool_id: toolCase.tool_id,
    requested_name: toolCase.requested_name ?? toolCase.tool_id,
    expectation: toolCase.expectation,
    executed: true,
    ok: toolCase.expectation === "expected_error",
    status: toolCase.expectation === "expected_error" ? "expected_error" : "unexpected_error",
    elapsed_ms,
    note: toolCase.note,
    title: "",
    output_excerpt: "",
    error: error.slice(0, 200).replaceAll("\n", "\\n"),
  }
}

