const pendingQuestion = Effect.fn("tool-catalog.pendingQuestion")(function* () {
  const questionSvc = yield* Question.Service
  for (;;) {
    const items = yield* questionSvc.list()
    const item = items[0]
    if (item) return item
    yield* Effect.sleep("10 millis")
  }
})

async function withServer<T>(fn: (url: string) => Promise<T>) {
  const server = Bun.serve({
    port: 0,
    fetch() {
      return new Response("<html><body><h1>tool latency</h1><p>hello fetch</p></body></html>", {
        headers: { "content-type": "text/html; charset=utf-8" },
      })
    },
  })
  try {
    return await fn(`http://127.0.0.1:${server.port}`)
  } finally {
    server.stop(true)
  }
}

